impl ViewContract {
    pub fn get_balance(env: Env, addr: Address) -> i128 {
        let bal = env.storage().instance().get(&addr).unwrap_or(0);
        env.storage().instance().set(&"last_viewed", &addr);
        bal
    }

    pub fn read_config(env: Env) -> u32 {
        env.storage().instance().get(&"config").unwrap_or(0)
    }

    pub fn set_config(env: Env, val: u32) {
        env.storage().instance().set(&"config", &val);
    }
}
